import{_ as a,o as s,c as t,ai as i}from"./chunks/framework.lvpqbiZd.js";const g=JSON.parse('{"title":"Guards","description":"","frontmatter":{},"headers":[],"relativePath":"code/guards/index.md","filePath":"code/guards/index.md"}'),r={name:"code/guards/index.md"};function n(o,e,d,l,h,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="guards" tabindex="-1">Guards <a class="header-anchor" href="#guards" aria-label="Permalink to “Guards”">​</a></h1><p>Guards are decorator-based access control primitives used across the Press codebase. They wrap API endpoints and document methods with pre-execution checks — verifying permissions, feature flags, plan entitlements, and authentication requirements before the underlying function runs.</p><h2 id="why-guards" tabindex="-1">Why Guards <a class="header-anchor" href="#why-guards" aria-label="Permalink to “Why Guards”">​</a></h2><p>Without guards, every endpoint would need inline permission checks, leading to duplicated logic and easy-to-miss security gaps. Guards centralise these checks into composable, declarative decorators that can be stacked on any function:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@frappe.whitelist</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@role_guard.api</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;billing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">@mfa.verify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">raise_error</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">def</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sensitive_billing_action</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">():</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    ...</span></span></code></pre></div><p>Each decorator in the stack runs top-to-bottom. If any guard fails, the function never executes — either raising an error or returning a safe default.</p><h2 id="available-guards" tabindex="-1">Available Guards <a class="header-anchor" href="#available-guards" aria-label="Permalink to “Available Guards”">​</a></h2><table tabindex="0"><thead><tr><th>Guard</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="./role-guard.html"><strong>Role</strong></a></td><td>Role-based access control (RBAC) for API endpoints, document actions, and individual documents via the <code>Press Role</code> doctype.</td></tr><tr><td><a href="./team-guard.html"><strong>Team</strong></a></td><td>Team-level access control — restricts document methods to team owners, admins, or members.</td></tr><tr><td><a href="./mfa.html"><strong>2FA</strong></a></td><td>Enforces two-factor authentication checks, verifying TOTP codes on sensitive endpoints.</td></tr><tr><td><a href="./site.html"><strong>Site</strong></a></td><td>Plan-based feature gating — ensures a site&#39;s plan includes access to a specific feature.</td></tr><tr><td><a href="./settings.html"><strong>Settings</strong></a></td><td>Feature flag checks against <code>Press Settings</code>, allowing functionality to be toggled at runtime without code changes.</td></tr></tbody></table><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to “Design Principles”">​</a></h2><ul><li><strong>Composable.</strong> Guards are standard Python decorators and can be freely stacked with each other, <code>@frappe.whitelist()</code>, <code>@protected()</code>, <code>@rate_limit()</code>, and any other decorator.</li><li><strong>Fail-safe.</strong> When a check fails, the default behaviour is to block execution. Most guards accept a <code>raise_error</code> flag to control whether they raise an exception or silently return a default value.</li><li><strong>Bypass-aware.</strong> Guards respect escape hatches like <code>ignore_permissions</code>, System Manager sessions, and team ownership so that administrative workflows are not blocked.</li><li><strong>Minimal overhead.</strong> Permission data is read from cached doctypes, keeping the per-request cost low.</li></ul><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to “Source”">​</a></h2><p>All guard modules live under <a href="https://github.com/frappe/press/tree/develop/press/guards" target="_blank" rel="noreferrer"><code>press/guards/</code></a>.</p>`,12)])])}const u=a(r,[["render",n]]);export{g as __pageData,u as default};
